// frontend/src/components/jobs/JobDetail.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api'; 

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [job, setJob] = useState(null);

    useEffect(() => {
        // Mengambil detail lowongan berdasarkan ID
        api.get(`/jobs/${id}`) 
            .then(res => {
                // Sesuaikan jika backend mengirim { data: ... }
                setJob(res.data.data || res.data);
            })
            .catch(err => console.error("Gagal memuat detail:", err));
    }, [id]);

    if (!job) return <div>Memuat data...</div>;

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <button onClick={() => navigate(-1)} style={{ marginBottom: '20px', cursor: 'pointer' }}>
                Kembali
            </button>
            <h2>{job.title}</h2>
            <p><strong>Gaji:</strong> {job.gaji}</p>
            <p><strong>Kategori:</strong> {job.kategori}</p>
            <div style={{ marginTop: '20px' }}>
                <h4>Deskripsi:</h4>
                <p>{job.desc}</p>
            </div>
        </div>
    );
};

// PENTING: Baris ini yang menyebabkan error jika tidak ada!
export default JobDetail;
